use ritual_spc_verification::SpcVerifier;

pub struct BuilderContext<Node: FullNodeTypes> {
    pub(crate) config_container: WithConfigs<<Node::Types as NodeTypes>::ChainSpec>,
    /// Shared SPC verifier instance
    pub(crate) spc_verifier: Arc<SpcVerifier<Node::Provider>>,
}

pub fn new(
    head: Head,
    provider: Node::Provider,
    executor: TaskExecutor,
    config_container: WithConfigs<<Node::Types as NodeTypes>::ChainSpec>,
) -> Self {
    use ritual_spc_verification::{ExecutorRegistry, SpcVerifier};
    let executor_registry = Arc::new(std::sync::RwLock::new(ExecutorRegistry::new(100)));
    let spc_verifier = Arc::new(
        SpcVerifier::new_from_env(executor_registry, provider.clone())
            .expect("FATAL: Failed to create SPC verifier"),
    );

    Self { head, provider, executor, config_container, spc_verifier }
}

pub const fn spc_verifier(&self) -> &Arc<SpcVerifier<Node::Provider>> {
    &self.spc_verifier
}
